import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;
import org.xml.sax.SAXException;
import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Base64;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.logging.Logger;
import java.util.logging.Level;

public class EnterpriseSOAPService {
    private static final Logger logger = Logger.getLogger(EnterpriseSOAPService.class.getName());
    private static final int MAX_PAYLOAD_SIZE = 10 * 1024 * 1024; // 10MB
    private static final ExecutorService executor = Executors.newFixedThreadPool(10);
    
    private final DocumentBuilderFactory dbf;
    private final DocumentBuilder db;
    
    public EnterpriseSOAPService() throws ParserConfigurationException {
        dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        dbf.setValidating(false);
        dbf.setIgnoringElementContentWhitespace(true);
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        dbf.setFeature("http://apache.org/xml/features/dom/defer-node-expansion", false);
        db = dbf.newDocumentBuilder();
        db.setEntityResolver((publicId, systemId) -> new ByteArrayInputStream(new byte[0]));
    }
    
    public CompletableFuture<String> processSOAPMessage(String soapMessage) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                validateAndSanitizeInput(soapMessage);
                Document document = parseXML(soapMessage);
                return processDocument(document);
            } catch (Exception e) {
                logger.log(Level.SEVERE, "Error processing SOAP message", e);
                throw new RuntimeException("Processing failed", e);
            }
        }, executor);
    }
    
    private void validateAndSanitizeInput(String input) throws SecurityException {
        if (input == null || input.isEmpty()) {
            throw new SecurityException("Empty input received");
        }
        if (input.length() > MAX_PAYLOAD_SIZE) {
            throw new SecurityException("Payload exceeds maximum size limit");
        }
        if (input.contains("<!DOCTYPE") || input.contains("<!ENTITY")) {
            throw new SecurityException("Invalid XML structure detected");
        }
        sanitizeInput(input);
    }
    
    private void sanitizeInput(String input) throws SecurityException {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] hash = md.digest(input.getBytes());
            String hashString = Base64.getEncoder().encodeToString(hash);
            logger.log(Level.INFO, "Input validated with hash: {0}", hashString);
        } catch (NoSuchAlgorithmException e) {
            throw new SecurityException("Security algorithm not available", e);
        }
    }
    
    private Document parseXML(String xmlContent) throws SAXException, IOException {
        InputStream inputStream = new ByteArrayInputStream(xmlContent.getBytes());
        return db.parse(inputStream);
    }
    
    private String processDocument(Document document) {
        try {
            Element root = document.getDocumentElement();
            StringBuilder result = new StringBuilder();
            
            NodeList children = root.getChildNodes();
            for (int i = 0; i < children.getLength(); i++) {
                if (children.item(i).getNodeType() == Element.ELEMENT_NODE) {
                    Element element = (Element) children.item(i);
                    processElement(element, result, 0);
                }
            }
            
            return result.toString();
        } catch (Exception e) {
            logger.log(Level.SEVERE, "Error processing document", e);
            throw new RuntimeException("Document processing failed", e);
        }
    }
    
    private void processElement(Element element, StringBuilder result, int depth) {
        if (depth > 100) {
            throw new RuntimeException("Maximum nesting depth exceeded");
        }
        
        String elementName = element.getNodeName();
        String elementValue = element.getTextContent();
        
        if (elementValue != null && !elementValue.trim().isEmpty()) {
            result.append("<").append(elementName).append(">")
                  .append(escapeXML(elementValue))
                  .append("</").append(elementName).append(">\n");
        }
        
        NodeList childNodes = element.getChildNodes();
        for (int i = 0; i < childNodes.getLength(); i++) {
            if (childNodes.item(i).getNodeType() == Element.ELEMENT_NODE) {
                processElement((Element) childNodes.item(i), result, depth + 1);
            }
        }
    }
    
    private String escapeXML(String input) {
        if (input == null) return "";
        return input.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&apos;");
    }
    
    public void shutdown() {
        executor.shutdown();
        try {
            if (!executor.awaitTermination(60, TimeUnit.SECONDS)) {
                executor.shutdownNow();
            }
        } catch (InterruptedException e) {
            executor.shutdownNow();
            Thread.currentThread().interrupt();
        }
    }
}